CREATE VIEW public_silver.stg_customers AS
 WITH source AS (
         SELECT customers.customer_id,
            customers.company_name,
            customers.contact_name,
            customers.contact_title,
            customers.address,
            customers.city,
            customers.region,
            customers.postal_code,
            customers.country,
            customers.phone,
            customers.fax,
            customers._ingested_at,
            customers._source_file
           FROM bronze.customers
        ), cleaned AS (
         SELECT (source.customer_id)::character varying(10) AS customer_id,
            (source.company_name)::character varying AS company_name,
            (source.contact_name)::character varying AS contact_name,
            (source.contact_title)::character varying AS contact_title,
            (source.address)::character varying AS address,
            (source.city)::character varying AS city,
            COALESCE((source.region)::character varying, 'N/A'::character varying) AS region,
            (source.postal_code)::character varying AS postal_code,
            (source.country)::character varying AS country,
            (source.phone)::character varying AS phone,
            (source.fax)::character varying AS fax,
                CASE source.country
                    WHEN 'USA'::text THEN 'América do Norte'::text
                    WHEN 'Canada'::text THEN 'América do Norte'::text
                    WHEN 'Mexico'::text THEN 'América Latina'::text
                    WHEN 'Brazil'::text THEN 'América Latina'::text
                    WHEN 'Venezuela'::text THEN 'América Latina'::text
                    WHEN 'Argentina'::text THEN 'América Latina'::text
                    WHEN 'UK'::text THEN 'Europa'::text
                    WHEN 'Germany'::text THEN 'Europa'::text
                    WHEN 'France'::text THEN 'Europa'::text
                    WHEN 'Spain'::text THEN 'Europa'::text
                    WHEN 'Italy'::text THEN 'Europa'::text
                    WHEN 'Sweden'::text THEN 'Europa'::text
                    WHEN 'Denmark'::text THEN 'Europa'::text
                    WHEN 'Norway'::text THEN 'Europa'::text
                    WHEN 'Finland'::text THEN 'Europa'::text
                    WHEN 'Belgium'::text THEN 'Europa'::text
                    WHEN 'Switzerland'::text THEN 'Europa'::text
                    WHEN 'Austria'::text THEN 'Europa'::text
                    WHEN 'Portugal'::text THEN 'Europa'::text
                    WHEN 'Poland'::text THEN 'Europa'::text
                    WHEN 'Ireland'::text THEN 'Europa'::text
                    ELSE 'Outros'::text
                END AS continent
           FROM source
          WHERE (source.customer_id IS NOT NULL)
        )
 SELECT customer_id,
    company_name,
    contact_name,
    contact_title,
    address,
    city,
    region,
    postal_code,
