CREATE VIEW public_silver.stg_employees AS
 WITH source AS (
         SELECT employees.employee_id,
            employees.last_name,
            employees.first_name,
            employees.title,
            employees.title_of_courtesy,
            employees.birth_date,
            employees.hire_date,
            employees.address,
            employees.city,
            employees.region,
            employees.postal_code,
            employees.country,
            employees.home_phone,
            employees.extension,
            employees.photo,
            employees.notes,
            employees.reports_to,
            employees.photo_path,
            employees._ingested_at,
            employees._source_file
           FROM bronze.employees
        ), cleaned AS (
         SELECT (source.employee_id)::integer AS employee_id,
            (source.first_name)::character varying AS first_name,
            (source.last_name)::character varying AS last_name,
            (((source.first_name || ' '::text) || source.last_name))::character varying AS full_name,
            (source.title)::character varying AS title,
            (source.title_of_courtesy)::character varying AS title_of_courtesy,
            (source.birth_date)::date AS birth_date,
            (source.hire_date)::date AS hire_date,
            (source.city)::character varying AS city,
            COALESCE((source.region)::character varying, 'N/A'::character varying) AS region,
            (source.country)::character varying AS country,
            (source.reports_to)::integer AS reports_to,
            (EXTRACT(year FROM age((CURRENT_DATE)::timestamp with time zone, ((source.hire_date)::date)::timestamp with time zone)))::integer AS years_tenure
           FROM source
          WHERE (source.employee_id IS NOT NULL)
        )
 SELECT employee_id,
    first_name,
    last_name,
    full_name,
    title,
    title_of_courtesy,
    birth_date,
    hire_date,
    city,
    region,
    country,
    reports_to,
    years_tenure
   FROM cleaned;


