-- Name: stg_order_details; Type: VIEW; Schema: public_silver; Owner: northwind_user
--

CREATE VIEW public_silver.stg_order_details AS
 WITH source AS (
         SELECT order_details.order_id,
            order_details.product_id,
            order_details.unit_price,
            order_details.quantity,
            order_details.discount,
            order_details._ingested_at,
            order_details._source_file
           FROM bronze.order_details
        ), cleaned AS (
         SELECT (source.order_id)::integer AS order_id,
            (source.product_id)::integer AS product_id,
            (source.unit_price)::numeric(10,2) AS unit_price,
            (source.quantity)::integer AS quantity,
            (source.discount)::numeric(5,4) AS discount,
            (((source.unit_price)::numeric * ((source.quantity)::integer)::numeric))::numeric(12,2) AS gross_revenue,
            ((((source.unit_price)::numeric * ((source.quantity)::integer)::numeric) * ((1)::numeric - (source.discount)::numeric)))::numeric(12,2) AS net_revenue,
            ((((source.unit_price)::numeric * ((source.quantity)::integer)::numeric) * (source.discount)::numeric))::numeric(12,2) AS discount_amount,
                CASE
                    WHEN ((source.discount)::numeric = (0)::numeric) THEN 'Sem Desconto'::text
                    WHEN ((source.discount)::numeric < 0.10) THEN 'Desconto Baixo (<10%)'::text
                    WHEN ((source.discount)::numeric < 0.20) THEN 'Desconto Médio (10-20%)'::text
                    ELSE 'Desconto Alto (>20%)'::text
                END AS discount_tier
           FROM source
          WHERE ((source.order_id IS NOT NULL) AND (source.product_id IS NOT NULL))
        )
 SELECT order_id,
    product_id,
    unit_price,
    quantity,
    discount,
    gross_revenue,
    net_revenue,
    discount_amount,
    discount_tier
   FROM cleaned;


ALTER VIEW public_silver.stg_order_details OWNER TO northwind_user;

