CREATE VIEW public_silver.stg_orders AS
 WITH source AS (
         SELECT orders.order_id,
            orders.customer_id,
            orders.employee_id,
            orders.order_date,
            orders.required_date,
            orders.shipped_date,
            orders.ship_via,
            orders.freight,
            orders.ship_name,
            orders.ship_address,
            orders.ship_city,
            orders.ship_region,
            orders.ship_postal_code,
            orders.ship_country,
            orders._ingested_at,
            orders._source_file
           FROM bronze.orders
        ), cleaned AS (
         SELECT (source.order_id)::integer AS order_id,
            (source.customer_id)::character varying(10) AS customer_id,
            (source.employee_id)::integer AS employee_id,
            (source.order_date)::date AS order_date,
            (source.required_date)::date AS required_date,
            (source.shipped_date)::date AS shipped_date,
            (source.ship_via)::integer AS shipper_id,
            (source.freight)::numeric(10,2) AS freight,
            (source.ship_name)::character varying AS ship_name,
            (source.ship_address)::character varying AS ship_address,
            (source.ship_city)::character varying AS ship_city,
            COALESCE((source.ship_region)::character varying, 'N/A'::character varying) AS ship_region,
            (source.ship_postal_code)::character varying AS ship_postal_code,
            (source.ship_country)::character varying AS ship_country,
            (EXTRACT(year FROM (source.order_date)::date))::integer AS order_year,
            (EXTRACT(month FROM (source.order_date)::date))::integer AS order_month,
            to_char(((source.order_date)::date)::timestamp with time zone, 'YYYY-MM'::text) AS order_year_month,
            ((source.shipped_date)::date - (source.order_date)::date) AS days_to_ship,
            ((source.required_date)::date - (source.order_date)::date) AS days_to_deadline,
                CASE
                    WHEN (source.shipped_date IS NULL) THEN 'Não Enviado'::text
                    WHEN ((source.shipped_date)::date > (source.required_date)::date) THEN 'Atrasado'::text
                    ELSE 'No Prazo'::text
                END AS delivery_status,
                CASE
                    WHEN ((source.shipped_date)::date > (source.required_date)::date) THEN 1
                    ELSE 0
                END AS is_late
           FROM source
          WHERE (source.order_id IS NOT NULL)
        )
 SELECT order_id,
    customer_id,
    employee_id,
    order_date,
    required_date,
    shipped_date,
    shipper_id,
    freight,
    ship_name,
    ship_address,
    ship_city,
    ship_region,
    ship_postal_code,
    ship_country,
    order_year,
    order_month,
    order_year_month,
    days_to_ship,
    days_to_deadline,
    delivery_status,
    is_late
   FROM cleaned;


