CREATE VIEW public_silver.stg_products AS
 WITH source AS (
         SELECT products.product_id,
            products.product_name,
            products.supplier_id,
            products.category_id,
            products.quantity_per_unit,
            products.unit_price,
            products.units_in_stock,
            products.units_on_order,
            products.reorder_level,
            products.discontinued,
            products._ingested_at,
            products._source_file
           FROM bronze.products
        ), cats AS (
         SELECT categories.category_id,
            categories.category_name,
            categories.description,
            categories.picture,
            categories._ingested_at,
            categories._source_file
           FROM bronze.categories
        ), sups AS (
         SELECT suppliers.supplier_id,
            suppliers.company_name,
            suppliers.contact_name,
            suppliers.contact_title,
            suppliers.address,
            suppliers.city,
            suppliers.region,
            suppliers.postal_code,
            suppliers.country,
            suppliers.phone,
            suppliers.fax,
            suppliers.homepage,
            suppliers._ingested_at,
            suppliers._source_file
           FROM bronze.suppliers
        ), cleaned AS (
         SELECT (p.product_id)::integer AS product_id,
            (p.product_name)::character varying AS product_name,
            (p.supplier_id)::integer AS supplier_id,
            (p.category_id)::integer AS category_id,
            (c.category_name)::character varying AS category_name,
            (s.company_name)::character varying AS supplier_name,
            (p.quantity_per_unit)::character varying AS quantity_per_unit,
            (p.unit_price)::numeric(10,2) AS unit_price,
            (p.units_in_stock)::integer AS units_in_stock,
            (p.units_on_order)::integer AS units_on_order,
            (p.reorder_level)::integer AS reorder_level,
            (p.discontinued)::integer AS discontinued,
                CASE
                    WHEN ((p.discontinued)::integer = 1) THEN true
                    ELSE false
                END AS is_discontinued,
                CASE
                    WHEN ((p.units_in_stock)::integer = 0) THEN 'Sem Estoque'::text
                    WHEN ((p.units_in_stock)::integer <= (p.reorder_level)::integer) THEN 'Estoque Crítico'::text
                    WHEN ((p.units_in_stock)::integer <= ((p.reorder_level)::integer * 2)) THEN 'Estoque Baixo'::text
                    ELSE 'Estoque OK'::text
                END AS stock_status
           FROM ((source p
             LEFT JOIN cats c ON (((p.category_id)::integer = (c.category_id)::integer)))
             LEFT JOIN sups s ON (((p.supplier_id)::integer = (s.supplier_id)::integer)))
          WHERE (p.product_id IS NOT NULL)
        )
 SELECT product_id,
    product_name,
    supplier_id,
    category_id,
    category_name,
    supplier_name,
    quantity_per_unit,
    unit_price,
    units_in_stock,
    units_on_order,
    reorder_level,
    discontinued,
    is_discontinued,
    stock_status
   FROM cleaned;


